<script>
const POST_URL = '${postUrl}';
let selectedFiles = [];

// File Upload Handling
const dropZone = document.getElementById('dropZone');
const fileInput = document.getElementById('fileInput');
const fileList = document.getElementById('fileList');

dropZone.addEventListener('click', () => fileInput.click());

dropZone.addEventListener('dragover', (e) => {
  e.preventDefault();
  dropZone.classList.add('drag-over');
});

dropZone.addEventListener('dragleave', () => {
  dropZone.classList.remove('drag-over');
});

dropZone.addEventListener('drop', (e) => {
  e.preventDefault();
  dropZone.classList.remove('drag-over');
  addFiles(e.dataTransfer.files);
});

fileInput.addEventListener('change', () => {
  addFiles(fileInput.files);
  fileInput.value = '';
});

function addFiles(files) {
  const allowed = ['.txt','.pdf','.docx','.md'];
  for (const f of files) {
    const ext = '.' + f.name.split('.').pop().toLowerCase();
    if (!allowed.includes(ext)) continue;
    if (f.size > 10 * 1024 * 1024) continue;
    if (!selectedFiles.find(s => s.name === f.name)) {
      selectedFiles.push(f);
    }
  }
  renderFiles();
}

function renderFiles() {
  fileList.innerHTML = selectedFiles.map((f, i) =>
    '<div class="file-item">' +
      '<span class="name">' + f.name + '</span>' +
      '<span class="size">' + (f.size / 1024).toFixed(1) + ' KB</span>' +
      '<button type="button" class="remove" onclick="removeFile(' + i + ')">&times;</button>' +
    '</div>'
  ).join('');
}

function removeFile(idx) {
  selectedFiles.splice(idx, 1);
  renderFiles();
}

// Form Submit
document.getElementById('presentationForm').addEventListener('submit', async (e) => {
  e.preventDefault();
  const btn = document.getElementById('submitBtn');
  const errorBanner = document.getElementById('errorBanner');
  errorBanner.classList.remove('active');

  const clientName = document.getElementById('clientName').value.trim();
  const presentationType = document.getElementById('presentationType').value;
  const meetingNotes = document.getElementById('meetingNotes').value.trim();
  const email = document.getElementById('email').value.trim();
  const numSlides = document.getElementById('numSlides').value || '10';

  if (!clientName || !meetingNotes || !email) {
    errorBanner.textContent = 'Bitte fuelle alle Pflichtfelder aus.';
    errorBanner.classList.add('active');
    return;
  }

  btn.disabled = true;
  showLoading();

  const formData = new FormData();
  formData.append('clientName', clientName);
  formData.append('presentationType', presentationType);
  formData.append('meetingNotes', meetingNotes);
  formData.append('email', email);
  formData.append('numSlides', numSlides);

  selectedFiles.forEach(f => formData.append('files', f));

  try {
    updateStep('KI analysiert deine Eingaben...');
    const res = await fetch(POST_URL, { method: 'POST', body: formData });
    if (!res.ok) throw new Error('Server-Fehler: ' + res.status);
    const data = await res.json();

    if (data.success) {
      showResult(data, email);
    } else {
      throw new Error(data.error || 'Unbekannter Fehler');
    }
  } catch (err) {
    hideLoading();
    errorBanner.textContent = 'Fehler: ' + err.message;
    errorBanner.classList.add('active');
    btn.disabled = false;
  }
});

function showLoading() {
  document.getElementById('loadingOverlay').classList.add('active');
}

function hideLoading() {
  document.getElementById('loadingOverlay').classList.remove('active');
}

function updateStep(text) {
  document.getElementById('loadingStep').textContent = text;
}

function showResult(data, email) {
  hideLoading();
  document.getElementById('formView').style.display = 'none';
  document.getElementById('resultView').classList.add('active');
  document.getElementById('resultEmail').textContent = email;
  document.getElementById('linkView').href = data.url || '#';
  document.getElementById('linkDownload').href = data.exportUrl || '#';
  if (!data.url) document.getElementById('linkView').style.display = 'none';
  if (!data.exportUrl) document.getElementById('linkDownload').style.display = 'none';
  document.getElementById('resultMeta').textContent = (data.cardCount || '') + ' Slides erstellt';
}

function resetForm() {
  document.getElementById('formView').style.display = 'block';
  document.getElementById('resultView').classList.remove('active');
  document.getElementById('presentationForm').reset();
  selectedFiles = [];
  renderFiles();
  document.getElementById('submitBtn').disabled = false;
  document.getElementById('errorBanner').classList.remove('active');
}
</script>
</body>
</html>`;

return [{ json: { html } }];

// Extract form fields from webhook body
const input = $input.first().json;
const body = input.body || input;

const clientName = (body.clientName || '').trim();
const presentationType = (body.presentationType || 'Angebot').trim();
const meetingNotes = (body.meetingNotes || '').trim();
const email = (body.email || '').trim();
const numSlides = parseInt(body.numSlides || '10', 10);

if (!clientName || !meetingNotes || !email) {
  return [{ json: { error: 'Pflichtfelder fehlen', success: false } }];
}

// Process uploaded binary files - extract text content
let fileTexts = [];
const binaryData = $input.first().binary || {};

for (const key of Object.keys(binaryData)) {
  const file = binaryData[key];
  const fileName = file.fileName || key;
  const mimeType = file.mimeType || '';

  try {
    // For text-based files, decode the base64 content
    if (mimeType.includes('text') || fileName.endsWith('.txt') || fileName.endsWith('.md')) {
      const content = Buffer.from(file.data, 'base64').toString('utf-8');
      fileTexts.push(`--- Datei: ${fileName} ---\n${content}`);
    } else {
      // For PDF/DOCX, we'll note them for downstream processing
      fileTexts.push(`--- Datei: ${fileName} (${mimeType}) --- [Inhalt wird separat extrahiert]`);
    }
  } catch (e) {
    fileTexts.push(`--- Datei: ${fileName} --- [Konnte nicht gelesen werden]`);
  }
}

const contextDocument = fileTexts.join('\n\n');
const sessionId = email;

return [{
  json: {
    clientName,
    presentationType,
    meetingNotes,
    email,
    numSlides,
    contextDocument,
    sessionId,
    success: true
  }
}];

