// Ergebnis formatieren
const status = $input.first().json;
const email = $('Eingabe verarbeiten').item.json.email;
const clientName = $('Eingabe verarbeiten').item.json.clientName;

const url = status.gammaUrl || status.url || '';
const exportUrl = status.exportUrl || status.pdfUrl || '';
const cardCount = status.cardCount || 0;

// HTML E-Mail Body
const htmlBody = `
<div style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background-color: #E20074; padding: 24px; text-align: center; border-radius: 6px 6px 0 0;">
    <h1 style="color: #FFFFFF; margin: 0; font-size: 22px;">Deine Pr\u00e4sentation ist fertig!</h1>
  </div>
  <div style="padding: 28px; background-color: #F8F8F8;">
    <p style="font-size: 15px; color: #333;">Deine Angebots-Pr\u00e4sentation f\u00fcr <strong>${clientName}</strong> wurde erfolgreich erstellt.</p>
    <p style="font-size: 15px; color: #333;"><strong>Anzahl Slides:</strong> ${cardCount}</p>
    <div style="margin: 28px 0; text-align: center;">
      ${url ? '<a href="' + url + '" style="display: inline-block; background-color: #E20074; color: #FFFFFF; padding: 14px 32px; text-decoration: none; border-radius: 4px; font-weight: bold; margin: 8px;">Pr\u00e4sentation ansehen</a>' : ''}
      ${exportUrl ? '<a href="' + exportUrl + '" style="display: inline-block; background-color: #333333; color: #FFFFFF; padding: 14px 32px; text-decoration: none; border-radius: 4px; font-weight: bold; margin: 8px;">PowerPoint herunterladen</a>' : ''}
    </div>
    <p style="font-size: 13px; color: #666;">Du kannst die Pr\u00e4sentation jederzeit \u00fcber die Links oben \u00f6ffnen und bearbeiten.</p>
  </div>
  <div style="padding: 16px; text-align: center; font-size: 12px; color: #999; border-top: 1px solid #eee;">
    Automatisch erstellt vom Pr\u00e4sentations-Generator | Deutsche Telekom MMS
  </div>
</div>`;

return [{
  json: {
    success: true,
    url,
    exportUrl,
    cardCount,
    email,
    clientName,
    emailBody: htmlBody
  }
}];

const response = $input.first().json;

// Track poll attempts using node-level static data
const nodeData = $getWorkflowStaticData('node');
const pollKey = 'poll_attempts';
const pollAttempts = (nodeData[pollKey] || 0) + 1;
nodeData[pollKey] = pollAttempts;

const MAX_ATTEMPTS = 10;
const status = response?.status || '';
const isCompleted = status === 'completed';
const isTimedOut = pollAttempts >= MAX_ATTEMPTS;
const hasFailed = status === 'failed' || status === 'error';

// Clean up when done
if (isCompleted || isTimedOut || hasFailed) {
  delete nodeData[pollKey];
}

return [{
  json: {
    ...response,
    status,
    isCompleted,
    isTimedOut,
    hasFailed,
    pollAttempts
  }
}];
